def solve(value: Array[Long], limit: Array[Long]): Long = {
    val n = value.length
    val indices = (0 until n).toArray
    // Sort indices by limit in ascending order, then by value in descending order
    val sortedIndices = indices.sortBy(i => (limit(i), -value(i)))

    var total = 0L
    var activeCount = 0L
    val active = ArrayBuffer[Long]()

    for (i <- sortedIndices) {
        if (activeCount < limit(i)) {
            active += value(i)
            total += value(i)
            activeCount += 1
            // After activation, check if any active elements need to be deactivated
            val toDeactivate = active.indices.filter(j => limit(i) <= activeCount)
            if (toDeactivate.nonEmpty) {
                activeCount -= toDeactivate.length
                // Remove the elements that are deactivated
                for (j <- toDeactivate.sorted.reverse) {
                    active.remove(j.toInt)
                }
            }
        }
    }

    total
}
